export function Octicon({ name, size = "1.5em" }: { name: OcticonName; size?: string }) {
  const paths = PATHS[name];

  return (
    <svg
      aria-hidden="true"
      viewBox="0 0 16 16"
      width={size}
      height={size}
      fill="currentColor"
      style={{ display: "inline-block", marginRight: "0.35em", verticalAlign: "-0.2em" }}
    >
      {Array.isArray(paths) ? (
        paths.map((path) => <path key={path} d={path} />)
      ) : (
        <path d={paths} />
      )}
    </svg>
  );
}
